import requests
import time
from typing import Optional

class OllamaClient:
    def __init__(self, host: str = "http://localhost:11434", timeout: float = 30.0):
        self.host = host
        self.timeout = timeout

    def _request(self, endpoint: str, **kwargs):
        url = f"{self.host}/{endpoint}"
        try:
            response = requests.post(url, timeout=self.timeout, **kwargs)
            response.raise_for_status()
            return response.json()
        except requests.RequestException as e:
            return {"error": str(e)}

    def generate(self, model: str, prompt: str, options: dict = None):
        payload = {
            "model": model,
            "prompt": prompt,
            "options": options or {}
        }
        return self._request("generate", json=payload)

    def pull(self, model: str):
        return self._request(f"pull/{model}")

    def list(self):
        return self._request("list")

    def delete(self, model: str):
        return self._request(f"delete/{model}")

    def chat(self, model: str, messages: list, options: dict = None):
        payload = {
            "model": model,
            "messages": messages,
            "options": options or {}
        }
        return self._request("chat", json=payload)

    def error(self, message: str):
        return {"error": message}
